    const result = nextGeneration([[0, 1], [1, 1]]);
    expect(result).toEqual([]);
  });
  it("should keep a live cell alive with exactly 2 neighbors (survival)", () => {
    // Three cells in a horizontal line - center cell (1,0) has exactly 2 neighbors
    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
    // Center cell (1,0) survives with 2 neighbors
    expect(result).toContainEqual([1, 0]);
  });
  it.todo("should keep a live cell alive with exactly 3 neighbors (survival)");
  it.todo("should kill a live cell with 4 neighbors (overpopulation)");
  it.todo("should bring a dead cell to life with exactly 3 live neighbors (reproduction)");
  it.todo("should keep a block pattern unchanged (still life)");
  it.todo("should oscillate a blinker pattern (horizontal to vertical)");
});

